class CustomBuildCommand(build):
    def run(self):
        build.run(self)
        self.execute_custom_setup()
    
    def execute_custom_setup(self):
        print("Running custom build setup...")
        self.download_resources()
    
    def download_resources(self):
        resources_dir = Path('build/resources')
        resources_dir.mkdir(parents=True, exist_ok=True)
        
        resources = {
            'config_template.json': 'https://raw.githubusercontent.com/example/repo/main/config.json',
            'data_model.yaml': 'https://raw.githubusercontent.com/example/repo/main/model.yaml',
        }
        
        print("Downloading additional resources...")
        for filename, url in resources.items():
            try:
                dest_path = resources_dir / filename
                print(f"  Downloading {filename}...")
                urllib.request.urlretrieve(url, dest_path)
                print(f"  Downloaded {filename} successfully")
            except Exception as e:
                print(f"  Warning: Could not download {filename}: {e}")


class CustomInstallCommand(install):
    def run(self):
        install.run(self)
        self.execute_custom_install()
    
    def execute_custom_install(self):
        print("\nExecuting custom installation tasks...")
        self.create_config_directories()
        self.copy_resources()
        self.create_default_config()
        self.setup_environment_variables()
        print("Custom installation completed successfully!\n")
    
    def create_config_directories(self):
        print("Creating configuration directories...")
        
        home_dir = Path.home()
        config_base = home_dir / '.internal_library'
        
        directories = [
            config_base,
            config_base / 'config',
            config_base / 'logs',
            config_base / 'cache',
            config_base / 'data',
            config_base / 'plugins',
        ]
        
        for directory in directories:
            directory.mkdir(parents=True, exist_ok=True)
            print(f"  Created: {directory}")
        
        gitignore_path = config_base / '.gitignore'
        if not gitignore_path.exists():
            with open(gitignore_path, 'w') as f:
                f.write("*.log\n*.cache\n__pycache__/\n")
    
    def copy_resources(self):
        print("Copying resource files...")
        
        home_dir = Path.home()
        config_base = home_dir / '.internal_library'
        resources_dir = Path('build/resources')
        
        if resources_dir.exists():
            for resource_file in resources_dir.glob('*'):
                dest = config_base / 'config' / resource_file.name
                if not dest.exists():
                    shutil.copy2(resource_file, dest)
                    print(f"  Copied: {resource_file.name} -> {dest}")
        else:
            print("  No resources to copy (build/resources not found)")
    
    def create_default_config(self):
        print("Creating default configuration...")
        
        home_dir = Path.home()
        config_base = home_dir / '.internal_library'
        config_file = config_base / 'config' / 'settings.json'
        
        if not config_file.exists():
            default_config = {
                'version': '1.0.0',
                'environment': 'development',
                'logging': {
                    'level': 'INFO',
                    'format': '%(asctime)s - %(name)s - %(levelname)s - %(message)s',
                    'log_dir': str(config_base / 'logs')
                },
                'cache': {
                    'enabled': True,
                    'cache_dir': str(config_base / 'cache'),
                    'max_size_mb': 500
                },
                'database': {
                    'type': 'sqlite',
                    'path': str(config_base / 'data' / 'app.db')
                },
                'api': {
                    'timeout': 30,
                    'retries': 3,
                    'base_url': 'https://api.example.com'
                },
                'features': {
                    'enable_plugins': True,
                    'auto_update': False
                }
            }
            
            with open(config_file, 'w') as f:
                json.dump(default_config, f, indent=2)
            print(f"  Created default config: {config_file}")
        else:
            print(f"  Config already exists: {config_file}")
    
    def setup_environment_variables(self):
        print("Setting up environment variables...")
        
        home_dir = Path.home()
        config_base = home_dir / '.internal_library'
        
        env_vars = {
            'INTERNAL_LIBRARY_HOME': str(config_base),
            'INTERNAL_LIBRARY_CONFIG': str(config_base / 'config'),
            'INTERNAL_LIBRARY_LOGS': str(config_base / 'logs'),
            'INTERNAL_LIBRARY_CACHE': str(config_base / 'cache'),
            'INTERNAL_LIBRARY_DATA': str(config_base / 'data'),
        }
        
        shell_rc_files = [
            home_dir / '.bashrc',
            home_dir / '.zshrc',
            home_dir / '.profile',
        ]
        
        env_content = "\n# Internal Library Environment Variables\n"
        for var_name, var_value in env_vars.items():
            env_content += f'export {var_name}="{var_value}"\n'
        env_content += "# End Internal Library Environment Variables\n"
        
        env_file = config_base / 'env_setup.sh'
        with open(env_file, 'w') as f:
            f.write(env_content)
        print(f"  Created environment setup script: {env_file}")
        
        for rc_file in shell_rc_files:
            if rc_file.exists():
                with open(rc_file, 'r') as f:
                    content = f.read()
                
                if 'INTERNAL_LIBRARY_HOME' not in content:
                    with open(rc_file, 'a') as f:
                        f.write(f'\n# Source Internal Library environment\n')
                        f.write(f'[ -f "{env_file}" ] && source "{env_file}"\n')
                    print(f"  Updated: {rc_file}")
        
        print("\nTo activate environment variables in current session, run:")
        print(f"  source {env_file}")


